+import { useState } from 'react';
+import { Link, useNavigate } from 'react-router-dom';
+import { useAuth } from '../../context/AuthContext';
+import { useCart } from '../../context/CartContext';
+import { ShoppingCartIcon, UserIcon, LogoutIcon, MenuIcon, XIcon } from '../UI/Icons';
+
+const Navbar = () => {
+  const { user, logout } = useAuth();
+  const { totalItems } = useCart();
+  const navigate = useNavigate();
+  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
+  const [userMenuOpen, setUserMenuOpen] = useState(false);
+
+  const handleLogout = () => {
+    logout();
+    navigate('/login');
+    setUserMenuOpen(false);
+    setMobileMenuOpen(false);
+  };
+
+  const closeMenus = () => {
+    setMobileMenuOpen(false);
+    setUserMenuOpen(false);
+  };
+
+  const navLinks = [
+    { to: '/', label: 'الرئيسية' },
+    { to: '/menu', label: 'القائمة' },
+    { to: '/orders', label: 'طلباتي' },
+  ];
+
+  const adminLinks = [
+    { to: '/staff/orders', label: 'لوحة متابعة الطلبات', roles: ['admin', 'staff'] },
+    { to: '/menu-management', label: 'إدارة القائمة', roles: ['admin', 'staff'] },
+    { to: '/dashboard', label: 'الإحصائيات والتقارير', roles: ['admin'] },
+  ];
+
+  return (
+    <nav className="bg-white shadow-md sticky top-0 z-50" aria-label="الشريط الرئيسي">
+      <div className="container mx-auto px-4">
+        <div className="flex justify-between items-center h-16">
+          {/* Logo */}
+          <Link to="/" className="text-2xl font-bold text-primary-600 hover:text-primary-700 transition-colors">
+            الشطبي
+          </Link>
+
+          {/* Desktop Navigation Links */}
+          <div className="hidden md:flex items-center space-x-6 space-x-reverse">
+            {navLinks.map(link => (
+              <Link
+                key={link.to}
+                to={link.to}
+                className="text-gray-700 hover:text-primary-600 font-medium transition-colors"
+              >
+                {link.label}
+              </Link>
+            ))}
+          </div>
+
+          {/* Right side icons and user menu */}
+          <div className="flex items-center space-x-4 space-x-reverse">
+            {/* Cart Icon */}
+            <Link
+              to="/cart"
+              className="relative p-2 text-gray-700 hover:text-primary-600 transition-colors rounded-full hover:bg-gray-100"
+              aria-label={`سلة التسوق ${totalItems > 0 ? `تحتوي على ${totalItems} عنصر` : 'فارغة'}`}
+            >
+              <ShoppingCartIcon className="w-6 h-6" />
+              {totalItems > 0 && (
+                <span className="absolute -top-1 -right-1 bg-primary-600 text-white text-xs rounded-full w-5 h-5 flex items-center justify-center font-medium">
+                  {totalItems}
+                </span>
+              )}
+            </Link>
+
+            {/* Desktop User Menu */}
+            <div className="hidden md:block relative">
+              <button
+                onClick={() => setUserMenuOpen(!userMenuOpen)}
+                className="flex items-center space-x-2 space-x-reverse p-2 text-gray-700 hover:text-primary-600 transition-colors rounded-full hover:bg-gray-100"
+                aria-expanded={userMenuOpen}
+                aria-haspopup="true"
+                aria-label="قائمة المستخدم"
+              >
+                <UserIcon className="w-6 h-6" />
+                <span className="font-medium">{user?.name}</span>
+              </button>
+
+              {userMenuOpen && (
+                <>
+                  <div
+                    className="fixed inset-0 z-40"
+                    onClick={() => setUserMenuOpen(false)}
+                  />
+                  <div className="absolute left-0 mt-2 w-56 bg-white rounded-lg shadow-lg py-2 border border-gray-100 z-50">
+                    <Link
+                      to="/profile"
+                      className="block px-4 py-2 text-gray-700 hover:bg-gray-50 transition-colors"
+                      onClick={() => setUserMenuOpen(false)}
+                    >
+                      الملف الشخصي
+                    </Link>
+
+                    {adminLinks.map(link => {
+                      if (link.roles.includes(user?.role)) {
+                        return (
+                          <Link
+                            key={link.to}
+                            to={link.to}
+                            className="block px-4 py-2 text-gray-700 hover:bg-gray-50 transition-colors"
+                            onClick={() => setUserMenuOpen(false)}
+                          >
+                            {link.label}
+                          </Link>
+                        );
+                      }
+                      return null;
+                    })}
+
+                    <hr className="my-1" />
+                    <button
+                      onClick={handleLogout}
+                      className="w-full text-right px-4 py-2 text-red-600 hover:bg-gray-50 transition-colors flex items-center space-x-2 space-x-reverse"
+                    >
+                      <LogoutIcon className="w-4 h-4" />
+                      <span>تسجيل الخروج</span>
+                    </button>
+                  </div>
+                </>
+              )}
+            </div>
+
+            {/* Mobile Hamburger Button */}
+            <button
+              className="md:hidden p-2 text-gray-700 hover:text-primary-600 transition-colors rounded-full hover:bg-gray-100"
+              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
+              aria-expanded={mobileMenuOpen}
+              aria-controls="mobile-menu"
+              aria-label={mobileMenuOpen ? 'إغلاق القائمة' : 'فتح القائمة'}
+            >
+              {mobileMenuOpen ? <XIcon className="w-6 h-6" /> : <MenuIcon className="w-6 h-6" />}
+            </button>
+          </div>
+        </div>
+
+        {/* Mobile Menu */}
+        <div
+          id="mobile-menu"
+          className={`md:hidden overflow-hidden transition-all duration-300 ease-in-out ${
+            mobileMenuOpen ? 'max-h-screen py-4' : 'max-h-0'
+          }`}
+        >
+          <div className="space-y-2 pb-4">
+            {navLinks.map(link => (
+              <Link
+                key={link.to}
+                to={link.to}
+                className="block px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
+                onClick={closeMenus}
+              >
+                {link.label}
+              </Link>
+            ))}
+
+            <hr className="my-2" />
+
+            {/* User info in mobile */}
+            {user && (
+              <div className="px-4 py-2 text-gray-600 text-sm">
+                مرحباً، {user.name}
+              </div>
+            )}
+
+            <Link
+              to="/profile"
+              className="block px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
+              onClick={closeMenus}
+            >
+              الملف الشخصي
+            </Link>
+
+            {adminLinks.map(link => {
+              if (link.roles.includes(user?.role)) {
+                return (
+                  <Link
+                    key={link.to}
+                    to={link.to}
+                    className="block px-4 py-2 text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
+                    onClick={closeMenus}
+                  >
+                    {link.label}
+                  </Link>
+                );
+              }
+              return null;
+            })}
+
+            
+
+
+            <button
+              onClick={handleLogout}
+              className="w-full text-right px-4 py-2 text-red-600 hover:bg-gray-100 rounded-lg transition-colors flex items-center space-x-2 space-x-reverse"
+            >
+              <LogoutIcon className="w-4 h-4" />
+              <span>تسجيل الخروج</span>
+            </button>
+          </div>
+        </div>
+      </div>
+    </nav>
+  );
+};
+
+export default Navbar;
